<?php
declare(strict_types=1);
namespace App\Core\Cloud;
final readonly class CloudService{public function __construct(private CloudFileRepository $files,private CloudFolderRepository $folders,private CloudRootRepository $roots){}
public function listFiles(int $tenantId,int $userId,?string $status=null): array{return $this->files->listByUser($tenantId,$userId,100,$status);} public function findFile(int $tenantId,int $userId,int $id): ?array{return $this->files->findByIdForUser($tenantId,$userId,$id);} public function archiveFile(int $tenantId,int $userId,int $id): string{return $this->files->archiveByIdForUser($tenantId,$userId,$id)?'Archivo actualizado correctamente.':'Archivo no encontrado.';} public function trashFile(int $tenantId,int $userId,int $id): string{return $this->files->trashByIdForUser($tenantId,$userId,$id)?'Archivo enviado a papelera.':'Archivo no encontrado.';} public function listFolders(int $tenantId,int $userId): array{return $this->folders->listByUser($tenantId,$userId);} public function listRoots(int $tenantId,int $userId): array{return $this->roots->listActiveByUser($tenantId,$userId);} 
public function createFolder(int $tenantId,int $userId,array $input): string{$rootId=(int)($input['root_id']??0);$root=$this->roots->findActiveByIdForUser($tenantId,$userId,$rootId);if($root===null){return 'No hay raíz Cloud activa para este usuario.';} $parentIdRaw=(string)($input['parent_folder_id']??'');$parentId=$parentIdRaw===''?null:(int)$parentIdRaw;$parentPrefix=null;if($parentId!==null){$parent=$this->folders->findActiveByIdForUser($tenantId,$userId,$parentId);if($parent===null){return 'Carpeta no encontrada.';}$parentPrefix=(string)($parent['prefix']??'');}$name=trim((string)($input['name']??''));if($name===''){return 'No se pudo guardar la carpeta.';} $folderType=(string)($input['folder_type']??'custom');$accessType=(string)($input['access_type']??'normal');$allowedFolderTypes=['root','cloud','mail','support','crm','erp','event','agenda','browser','ai','task','system','custom'];$allowedAccessTypes=['normal','secure','unlocked'];if(!in_array($folderType,$allowedFolderTypes,true)||!in_array($accessType,$allowedAccessTypes,true)){return 'No se pudo guardar la carpeta.';} $prefixBase=$parentPrefix??(string)($root['root_prefix']??'');$prefix=$this->buildPrefix($prefixBase,$name);$ok=$this->folders->create([':tenant_id'=>$tenantId,':user_id'=>$userId,':bucket_id'=>(int)($root['bucket_id']??0),':root_id'=>$rootId,':parent_folder_id'=>$parentId,':name'=>$name,':prefix'=>$prefix,':folder_type'=>$folderType,':access_type'=>$accessType,':found_in_s3'=>0,':is_system'=>0,':is_deleted'=>0]);return $ok?'Carpeta creada correctamente.':'No se pudo guardar la carpeta.';}
public function trashFolder(int $tenantId,int $userId,int $id): string{return $this->folders->trashByIdForUser($tenantId,$userId,$id)?'Carpeta enviada a papelera.':'Carpeta no encontrada.';}
private function buildPrefix(string $base,string $name): string{$slug=trim((string)preg_replace('/[^a-z0-9]+/i','-',strtolower($name)),'-');if($slug===''){$slug='folder';}return rtrim($base,'/').'/'.$slug.'/';}}
